class ByteStream
{
public:
  explicit ByteStream( uint64_t capacity )
  {
    _capacity = capacity;
    _buffer.resize(_vector_size);
  };

  std::vector&lt;char&gt; _buffer = {};
  bool _close = false;
  bool _finish = false;
  uint64_t _bytes_pushed = 0;
  uint64_t _bytes_popped = 0;
  uint64_t _size = 0;
  uint64_t _update_flag = 0;
  uint64_t _vector_size = 0xffffff;

  uint64_t _head = 0;
  uint64_t _tail = 0;
  // Helper functions (provided) to access the ByteStream&#039;s Reader and Writer interfaces
  Reader&amp; reader();
  const Reader&amp; reader() const;
  Writer&amp; writer();
  const Writer&amp; writer() const;


  void set_error() { _error = true; };       // Signal that the stream suffered an error.
  bool has_error() const { return _error; }; // Has the stream had an error?

protected:
  // Please add any additional state to the ByteStream here, and not to the Writer and Reader interfaces.
  uint64_t _capacity = 0;
  bool _error = false;
};

class Writer : public ByteStream
{
public:
  void push( std::string data ); // Push data to stream, but only as much as available capacity allows.
  void close();                  // Signal that the stream has reached its ending. Nothing more will be written.

  bool is_closed() const;              // Has the stream been closed?
  uint64_t available_capacity() const; // How many bytes can be pushed to the stream right now?
  uint64_t bytes_pushed() const;       // Total number of bytes cumulatively pushed to the stream
};

class Reader : public ByteStream
{
public:
  std::string_view peek() const; // Peek at the next bytes in the buffer
  void pop( uint64_t len );      // Remove `len` bytes from the buffer

  bool is_finished() const;        // Is the stream finished (closed and fully popped)?
  uint64_t bytes_buffered() const; // Number of bytes currently buffered (pushed and not popped)
  uint64_t bytes_popped() const;   // Total number of bytes cumulatively popped from stream
};

/*
 * read: A (provided) helper function thats peeks and pops up to `len` bytes
 * from a ByteStream Reader into a string;
 */
void read( Reader&amp; reader, uint64_t len, std::string&amp; out );

byte_stream.cc
#include &quot;byte_stream.hh&quot;
#include &lt;iostream&gt;
#include &lt;vector&gt; 

using namespace std;

bool Writer::is_closed() const
{
  return _close;
}

void Writer::push( string data )
{
  uint64_t len = data.size();
  if ( len &gt; Writer::available_capacity() )
  {
    len = Writer::available_capacity();
  }
  _bytes_pushed += len;
  _update_flag += len;
  _size += len;
  if (_update_flag &gt; _vector_size)
  {
    int tmphead = 0;
    for(size_t i = _tail; i &lt; _head; i++)
    {
      _buffer[tmphead] = _buffer[_tail];
      tmphead++;
      _tail++;
    }
    _tail = 0;
    _head = tmphead;
    _update_flag = len;
  }
  for (size_t i = 0; i &lt; len; i++) {
    _buffer[_head] = data[i];
    _head++;
  }
  return;
}

void Writer::close()
{
  _close = true;
  if (_size == 0)
    _finish = true;
  return;
}

uint64_t Writer::available_capacity() const
{
  return _capacity - _size;
}

uint64_t Writer::bytes_pushed() const
{
  return _bytes_pushed;
}

bool Reader::is_finished() const
{
  return _finish;
}

uint64_t Reader::bytes_popped() const
{
  return _bytes_popped;
}

string_view Reader::peek() const
{
  string_view tmp = string_view( &amp;(_buffer[_tail]), _size );
  return tmp;
}

void Reader::pop( uint64_t len )
{
  if ( len &gt; Reader::bytes_buffered() )
  {
    set_error();
    return;
  }
  _bytes_popped += len;
  _size -= len;
  _tail += len;

  if (!_size &amp;&amp; _close)
    _finish = true;

  return;
}

uint64_t Reader::bytes_buffered() const
{
  return _size;
}

