switch (insn-&gt;id)
{
  case ARM64_INS_B: // B 代表块结束，但是不一定 func 结束
    self-&gt;eob = TRUE; // end of block
    self-&gt;eoi = gum_arm64_branch_is_unconditional (insn); // end of Interrupt
    break;
  case ARM64_INS_BR:
  case ARM64_INS_BRAA:
  case ARM64_INS_BRAAZ:
  case ARM64_INS_BRAB:
  case ARM64_INS_BRABZ:
  case ARM64_INS_RET:
  case ARM64_INS_RETAA:
  case ARM64_INS_RETAB: // BR，RET 代表块和逻辑结束
    self-&gt;eob = TRUE;
    self-&gt;eoi = TRUE;
    break;
  case ARM64_INS_BL:
  case ARM64_INS_BLR:
  case ARM64_INS_BLRAA:
  case ARM64_INS_BLRAAZ:
  case ARM64_INS_BLRAB:
  case ARM64_INS_BLRABZ: // BL 会返回代表块结束，逻辑没结束
    self-&gt;eob = TRUE;
    self-&gt;eoi = FALSE;
    break;
  case ARM64_INS_CBZ:
  case ARM64_INS_CBNZ:
  case ARM64_INS_TBZ:
  case ARM64_INS_TBNZ: // 条件跳转会返回代表块结束，逻辑没结束
    self-&gt;eob = TRUE;
    self-&gt;eoi = FALSE;
    break;
  default:
    self-&gt;eob = FALSE;
    break;
}

